import { useState } from "react";
import { useTranslation } from "react-i18next";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from "@/components/ui/alert-dialog";
import { Plus, Search, Building2, Trash2, Edit, Eye, EyeOff, Coffee } from "lucide-react";
import { useBrands, useDeleteBrand } from "@/hooks/useBrands";
import { BrandFormDialog } from "@/components/admin/BrandFormDialog";
import { useLocalizedContent } from "@/hooks/useLocalizedContent";
import { useBatchUpdateRestaurants } from "@/hooks/useAdmin";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";

const AdminBrands = () => {
  const { t } = useTranslation();
  const { data: brands, isLoading } = useBrands();
  const deleteBrand = useDeleteBrand();
  const batchUpdateRestaurants = useBatchUpdateRestaurants();
  const { getLocalizedField } = useLocalizedContent();
  const [searchQuery, setSearchQuery] = useState("");

  // Fetch restaurants to get brand associations
  const { data: restaurants } = useQuery({
    queryKey: ["brand-restaurants"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("restaurants")
        .select("id, brand_id, visible")
        .not("brand_id", "is", null);
      if (error) throw error;
      return data;
    },
  });

  const filteredBrands = brands?.filter((brand) =>
    brand.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
    brand.name_en?.toLowerCase().includes(searchQuery.toLowerCase()) ||
    brand.name_pt?.toLowerCase().includes(searchQuery.toLowerCase())
  );

  if (isLoading) {
    return <div className="text-center">{t("common.loading")}</div>;
  }

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl md:text-3xl font-bold mb-2">{t("admin.brand.title")}</h1>
          <p className="text-muted-foreground">{t("admin.brand.subtitle")}</p>
        </div>
        <BrandFormDialog
          trigger={
            <Button>
              <Plus className="mr-2 h-4 w-4" />
              {t("admin.brand.create")}
            </Button>
          }
        />
      </div>

      {/* Search */}
      <Card>
        <CardContent className="pt-6">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-muted-foreground" />
            <Input
              placeholder={t("admin.brand.search")}
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="pl-9"
            />
          </div>
        </CardContent>
      </Card>

      {/* Brand List */}
      <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
        {filteredBrands?.map((brand) => (
          <Card key={brand.id} className="overflow-hidden">
            {brand.image_url && (
              <div className="aspect-video overflow-hidden">
                <img
                  src={brand.image_url}
                  alt={brand.name}
                  className="w-full h-full object-cover"
                />
              </div>
            )}
            <CardHeader className="pb-2">
              <div className="flex items-start justify-between gap-2">
                <div className="flex items-center gap-3">
                  {brand.logo_url ? (
                    <img
                      src={brand.logo_url}
                      alt={`${brand.name} logo`}
                      className="w-10 h-10 object-contain rounded-lg bg-muted p-1"
                    />
                  ) : (
                    <div className="w-10 h-10 rounded-lg bg-primary/10 flex items-center justify-center">
                      <Building2 className="w-5 h-5 text-primary" />
                    </div>
                  )}
                  <div>
                    <CardTitle className="text-lg">{getLocalizedField(brand, "name")}</CardTitle>
                    <CardDescription className="text-xs">
                      {brand.name !== brand.name_en && brand.name_en && (
                        <span className="mr-2">{brand.name_en}</span>
                      )}
                    </CardDescription>
                  </div>
                </div>
              </div>
            </CardHeader>
            <CardContent className="pt-0">
              {(brand.intro_zh || brand.intro_en || brand.intro_pt) && (
                <div 
                  className="text-sm text-muted-foreground line-clamp-2 mb-4 prose prose-sm max-w-none
                    [&_p]:m-0 [&_*]:text-muted-foreground"
                  dangerouslySetInnerHTML={{ 
                    __html: getLocalizedField(brand, "intro") || "" 
                  }}
                />
              )}
              <div className="flex flex-col gap-2">
                {/* Show/Hide all restaurants for this brand */}
                {(() => {
                  const brandRestaurants = restaurants?.filter(r => r.brand_id === brand.id) || [];
                  if (brandRestaurants.length === 0) return null;
                  const brandIds = brandRestaurants.map(r => r.id);
                  const visibleCount = brandRestaurants.filter(r => r.visible).length;
                  return (
                    <div className="flex gap-2">
                      <Button
                        variant="outline"
                        size="sm"
                        className="flex-1"
                        onClick={() => batchUpdateRestaurants.mutate({ ids: brandIds, updates: { visible: true } })}
                      >
                        <Eye className="mr-1 h-4 w-4" />
                        {t("admin.brand.showAll", "显示全部")} ({visibleCount}/{brandRestaurants.length})
                      </Button>
                      <Button
                        variant="outline"
                        size="sm"
                        className="flex-1"
                        onClick={() => batchUpdateRestaurants.mutate({ ids: brandIds, updates: { visible: false } })}
                      >
                        <EyeOff className="mr-1 h-4 w-4" />
                        {t("admin.brand.hideAll", "隐藏全部")}
                      </Button>
                    </div>
                  );
                })()}
                <div className="flex gap-2">
                <BrandFormDialog
                  brand={brand}
                  trigger={
                    <Button variant="outline" size="sm" className="flex-1">
                      <Edit className="mr-2 h-4 w-4" />
                      {t("common.edit")}
                    </Button>
                  }
                />
                <AlertDialog>
                  <AlertDialogTrigger asChild>
                    <Button variant="outline" size="sm">
                      <Trash2 className="h-4 w-4" />
                    </Button>
                  </AlertDialogTrigger>
                  <AlertDialogContent>
                    <AlertDialogHeader>
                      <AlertDialogTitle>{t("admin.brand.deleteConfirm")}</AlertDialogTitle>
                      <AlertDialogDescription>
                        {t("admin.brand.deleteWarning")}
                      </AlertDialogDescription>
                    </AlertDialogHeader>
                    <AlertDialogFooter>
                      <AlertDialogCancel>{t("common.cancel")}</AlertDialogCancel>
                      <AlertDialogAction onClick={() => deleteBrand.mutate(brand.id)}>
                        {t("common.delete")}
                      </AlertDialogAction>
                    </AlertDialogFooter>
                  </AlertDialogContent>
                </AlertDialog>
                </div>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>

      {filteredBrands?.length === 0 && (
        <Card>
          <CardContent className="py-12 text-center">
            <Building2 className="mx-auto h-12 w-12 text-muted-foreground/50 mb-4" />
            <p className="text-muted-foreground">{t("admin.brand.empty")}</p>
          </CardContent>
        </Card>
      )}
    </div>
  );
};

export default AdminBrands;
